INSERT INTO `albums` (`id`, `title`, `title_initial`, `artist_id`, `release_year`, `cover_url`, `description`, `created_by`, `created_at`, `updated_at`) VALUES (1, 'Fear of a Blank Planet', 'F', 5, 2007, 'https://p2.music.126.net/2oXoRLchdRkT6FVWAzkL4Q==/109951165328013759.jpg', 'Fear of a Blank Planet is the ninth studio album by Porcupine Tree. The concept of the album was heavily influenced by Bret Easton Ellis’ novel Lunar Park.\n\nThe lyrics deal with two typical neurobehavioural developmental disorders affecting teenagers in the 21st century: bipolar disorder and attention deficit disorder, and also with other common behaviour tendencies of youth like escapism through prescription drugs, social alienation caused by technology, and a feeling of vacuity—a product of information overload by the mass media\n\nSteven Wilson described the main character of the story as “…this kind of terminally bored kid, anywhere between 10 and 15 years old, who spends all his daylight hours in his bedroom with the curtains closed, playing on his PlayStation, listening to his iPod, texting his friends on his cell phone, looking at hardcore pornography on the Internet, downloading music, films, news, violence…”.\n\nPorcupine Tree：\n\nSteven Wilson – vocals, guitars, piano, keyboards\n\nRichard Barbieri – keyboards and synthesizers\n\nColin Edwin – bass guitars\n\nGavin Harrison – drums\n\nAdditional musicians：\n\nAlex Lifeson – guitar solo on “Anesthetize”\n\nRobert Fripp – soundscapes on “Way Out of Here”\n\nJohn Wesley – backing vocals\n\nOrchestra – London Session Orchestr', NULL, '2026-01-31 09:40:59', '2026-03-02 12:55:38');
