INSERT INTO `albums` (`id`, `title`, `title_initial`, `artist_id`, `release_year`, `cover_url`, `description`, `created_by`, `created_at`, `updated_at`) VALUES (7, 'To the Bone', 'T', 22, 2017, 'https://p1.music.126.net/cQNZKwDLcbaCwi6ZrW4XIQ==/18149638440522613.jpg', 'steven wilson的一张个人专辑，全是他喜欢的pop rock，听感整体不错。', NULL, '2026-02-12 11:11:48', '2026-03-02 12:55:39');
INSERT INTO `albums` (`id`, `title`, `title_initial`, `artist_id`, `release_year`, `cover_url`, `description`, `created_by`, `created_at`, `updated_at`) VALUES (8, 'In the Court of the Crimson King', 'I', 23, 1971, 'https://p1.music.126.net/Nd_nlHnVPnCcPzw7q0yQmQ==/109951172370337996.jpg', 'The album starts with a terrifying introduction for those unfamiliar with King Crimson’s musicality or progressive rock. In fact, it’s a punch in the gut. Obviously, nothing on this album came from a creative vacuum—the influence of Sgt. Pepper’s on this track is notable. The band members made it clear — King Crimson wouldn’t have existed without The Beatles. The dissonance and sound collages, for example, are strikingly similar to ‘A Day In The Life.’ I think the most incredible thing about this song is the polyrhythmic sections. It’s quite difficult for musicians to execute this as well as it’s done on this track. ‘A Love Supreme’ (1965) by John Coltrane was also a starting point when it comes to harmonic exploration, which evidently influenced many bands during this period.', NULL, '2026-02-12 12:41:27', '2026-03-02 12:55:39');
